#include <vector>
#include <algorithm>
#include <climits>

long long solve(std::vector<long long> nums, long long k) {
    if (nums.size() == 1) {
        return 0;
    }

    std::sort(nums.begin(), nums.end());

    long long min_remove = nums.size(); // Maximum possible removals

    for (int i = 0; i < nums.size(); ++i) {
        // Try to keep nums[i] as the minimum and find the largest j where nums[j] <= k * nums[i]
        int j = std::upper_bound(nums.begin() + i, nums.end(), k * nums[i]) - nums.begin();
        int count = j - i;
        min_remove = std::min(min_remove, nums.size() - count);
    }

    return min_remove;
}

